{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-heater-multi-action-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "partial",
  "requires_confirmation": true,
  "summary": "当前围绕已选中的进料流股 feed-1 与加热器 heater-1 的缺失规格问题生成候选提案：为 Cold Feed 补充缺失的流量规格占位，并为 Feed Heater 补充缺失的出口温度目标占位。",
  "answers": [
    {
      "summary": "针对 feed-1 与 heater-1 的两个直接报错，提出两个局部、可审查的候选补丁，占位补全求解所需规格，不改动拓扑。",
      "issues": [
        {
          "title": "feed-1 缺少流量规格",
          "details": "诊断指出 Cold Feed 缺少流量 specification，当前已知仅有温度和压力。",
          "citations": [
            "diag-1",
            "flowdoc-stream-1"
          ]
        },
        {
          "title": "heater-1 缺少出口温度目标",
          "details": "诊断指出 Feed Heater 处于 outlet_temperature 控制模式，但未设置对应的出口温度目标。",
          "citations": [
            "diag-2",
            "flowdoc-unit-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 Cold Feed 添加流量规格占位",
          "target": {
            "type": "stream",
            "id": "feed-1"
          },
          "rationale": "该流股被直接诊断为缺少流量规格；补充占位可将修改限制在当前选中的目标对象上，避免臆测具体数值。",
          "patch": {
            "spec_placeholders": {
              "flow_rate": {
                "required": true,
                "reason": "Missing flow rate specification reported by diagnostics."
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "flowdoc-stream-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为 Feed Heater 添加出口温度目标占位",
          "target": {
            "type": "unit",
            "id": "heater-1"
          },
          "rationale": "该设备已配置为 outlet_temperature 控制模式，诊断明确指出缺少出口温度目标；添加参数占位可保持最小修改且不改变连接关系。",
          "patch": {
            "parameter_placeholders": {
              "outlet_temperature_target_c": {
                "required": true,
                "reason": "Outlet temperature control mode requires a target temperature."
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-2",
            "flowdoc-unit-1"
          ]
        }
      ],
      "confidence": 0.95,
      "citations": [
        "diag-1",
        "diag-2",
        "flowdoc-stream-1",
        "flowdoc-unit-1"
      ]
    }
  ]
}
